const ahora = new Date();
const en4h  = new Date(ahora.getTime() + 4 * 3600000);
const pqrs  = $input.all().map(i => i.json);

const vencidas = pqrs.filter(p => p.fecha_limite_sla && new Date(p.fecha_limite_sla) < ahora);
const en_riesgo = pqrs.filter(p => p.fecha_limite_sla && new Date(p.fecha_limite_sla) >= ahora && new Date(p.fecha_limite_sla) <= en4h);

if (vencidas.length === 0 && en_riesgo.length === 0) {
  return [{ json: { sin_alertas: true, vencidas: [], en_riesgo: [] } }];
}

return [{ json: { sin_alertas: false, vencidas, en_riesgo, total_criticas: vencidas.length + en_riesgo.length } }];

const { vencidas } = $input.first().json;
const results = [];
for (const pqr of vencidas) {
  results.push({ json: { id: pqr.id, estado: 'vencida', prioridad: 'alta' } });
}
return results.length ? results : [{ json: { skipped: true } }];

